import{_ as r,o as i,c as a,ag as t}from"./chunks/framework.DXGyWiRo.js";const n="/images/lekt5202.jpg",l="/images/lekt5203.jpg",o="/images/lekt5204.jpg",s="/images/lekt5209.jpg",d="/images/lekt5205.jpg",u="/images/lekt5206.jpg",h="/images/lekt5207.jpg",b="/images/lekt5210.jpg",p="/images/lekt5212.jpg",m="/images/lekt5213.jpg",c="/images/lekt5214.jpg",g="/images/lekt5208.jpg",f="/images/lekt5215.jpg",k="/images/lekt5217.jpg",q="/images/lekt5216.jpg",w="/images/lekt5201.jpg",K=JSON.parse('{"title":"Lektion 52","description":"","frontmatter":{},"headers":[],"relativePath":"lektionen/lektion52.md","filePath":"lektionen/lektion52.md"}'),z={name:"lektionen/lektion52.md"};function v(P,e,_,S,B,A){return i(),a("div",null,[...e[0]||(e[0]=[t('<div class="info custom-block github-alert"><p class="custom-block-title">Zitierweise &amp; Rechte</p><p>Dieses Kapitel ist Teil des Sanskritkurses. Details zum Copyright und zur Zitierweise der Ursprungsfassung siehe: <a href="/impressum">Impressum &amp; Copyright</a></p></div><h1 id="lektion-52" tabindex="-1">Lektion 52 <a class="header-anchor" href="#lektion-52" aria-label="Permalink to &quot;Lektion 52&quot;">​</a></h1><h2 id="ubersicht" tabindex="-1">Übersicht <a class="header-anchor" href="#ubersicht" aria-label="Permalink to &quot;Übersicht&quot;">​</a></h2><ul><li>52.1. Neutrum der Stämme auf -i und -u</li><li>52.2. Nominalbildung <ul><li>52.2.1. PPP + -vant: Partizip der Vergangenheit Parasmaipada</li><li>52.2.2. तद्धित-Suffix -maya / -mayī</li><li>52.2.3. तद्धित-Suffix -eya</li></ul></li><li>52.3. Adverbialbildung: Adverbialsuffix -śas</li><li>52.4. Verbalkomposita, die ausdrücken, dass etwas zu etwas wird oder gemacht wird, was es vorher nicht ist (अभुततद्भावः) <ul><li>52.4.1. cvi-Bildungen</li><li>52.4.2. Suffix -sāt</li></ul></li><li>52.5. Wortwiederholungen (द्विरुक्तम्)</li><li>52.6. Das Zahlwort (सम्ख्या f.) <ul><li>52.6.1. Kardinalzahlen <ul><li>52.6.1.1. Zahladjektive (für 1 bis 19)</li><li>52.6.1.2. Zahlsubstantive (für 19ff.)</li><li>52.6.1.3. Syntaktisches zu den Kardinalzahlen</li></ul></li><li>52.6.2. Ordinalzahlen</li><li>52.6.3. Zahladverbien</li><li>52.6.4. Zahladjektive</li><li>52.6.5. Komposita mit Kardinalzahlen im Vorderglied</li></ul></li><li>52.7. Wortliste</li><li>52.8. Übersetzungsübung</li><li>52.9. Aufgaben während der Semesterferien</li></ul><h2 id="_52-1-neutrum-der-stamme-auf-i-und-u" tabindex="-1">52.1. Neutrum der Stämme auf -i und -u <a class="header-anchor" href="#_52-1-neutrum-der-stamme-auf-i-und-u" aria-label="Permalink to &quot;52.1. Neutrum der Stämme auf -i und -u&quot;">​</a></h2><p>Vor vokalisch anlautenden Endungen wird ein -n- eingeschoben, dies ist ein Einfluss der n-Stämme (-in).</p><p>|   | वारि n.<br> &quot;Wasser&quot; | मधु n.<br> &quot;Honig&quot; | | --- | --- | --- | | एकवचनम्</p><p>|   |   | | प्रथमा, द्वितीया | वारि | मधु | | तृतीया | वारिणा | मधुना | | चतुर्थी | वारिणे | मधुने | | पञ्चमी | वारिणस् | मधुनस् | | षष्ठी | वारिणस् | मधुनस् | | सप्तमी | वारिणि | मधुनि | | आमन्त्रितम् | वारि<br> वारे | मधु<br> मधो | |   |   |   | |</p><p>बहुवचनम्</p><p>|   |   | | प्रथमा, द्वितीया, आमन्त्रितम् | वारीणि | मधूनि | | तृतीया | वारिभिस् | मधुभिस् | | चतुर्थी | वारिभ्यस् | मधुभ्यस् | | पञ्चमी | वारिभ्यस् | मधुभ्यस् | | षष्ठी | वारीणाम् | मधूनाम् | | सप्तमी | वारिषु | मधुषु |</p><h2 id="_52-2-nominalbildung" tabindex="-1">52.2. Nominalbildung <a class="header-anchor" href="#_52-2-nominalbildung" aria-label="Permalink to &quot;52.2. Nominalbildung&quot;">​</a></h2><h3 id="_52-2-1-ppp-vant-partizip-der-vergangenheit-parasmaipada" tabindex="-1">52.2.1. PPP + -vant: Partizip der Vergangenheit Parasmaipada <a class="header-anchor" href="#_52-2-1-ppp-vant-partizip-der-vergangenheit-parasmaipada" aria-label="Permalink to &quot;52.2.1. PPP + -vant: Partizip der Vergangenheit Parasmaipada&quot;">​</a></h3><p>Ein Partizip Parasmaipada der Vergangenheit wird so gebildet:</p><p>PPP + -vant / fem.: vatī</p><p>Deklination wie die Stämme auf -vant bzw. f. देवी</p><p>Beispiele:</p><blockquote><p>कृतवन्त् (kṛta-vant) / कृतवती &quot;einer/eine, der/die getan hat&quot;</p><p>भिन्नवन्त् &quot;einer, der gespalten hat&quot;</p></blockquote><h3 id="_52-2-2-तद्धित-suffix-maya-mayi" tabindex="-1">52.2.2. तद्धित-Suffix -maya / -mayī <a class="header-anchor" href="#_52-2-2-तद्धित-suffix-maya-mayi" aria-label="Permalink to &quot;52.2.2. तद्धित-Suffix -maya / -mayī&quot;">​</a></h3><p>Das तद्धित-Suffix -maya / f.: -mayī bildet zu Substantiven Adjektive der Bedeutung</p><ul><li>&quot;gemacht aus&quot;</li><li>&quot;bestehend aus&quot;</li><li>&quot;reich an&quot;</li></ul><p>Vor -maya müssen (wie vor -मात्र) auslautende Verschlusslaute der Pausaform durch den ihnen entsprechenden Nasal ersetzt werden.</p><p>Beispiele:</p><blockquote><p>अन्नमय 3 &quot;reich an Speise&quot;</p><p>चिन्मय 3 (zu चित् f. &quot;Intellekt&quot;) &quot;aus Denken / Verstand bestehend&quot;</p><p>वाङ्मय 3 (zu वाच् f. &quot;Sprache&quot;) &quot;aus Rede bestehend&quot;</p><p>सोममय 3 &quot;aus Soma gemacht, aus Soma bestehend&quot;</p></blockquote><p>Nomina auf -maya werden gelegentlich als neutrale Substantive gebraucht und bezeichnen dann Überfluss an dem, was durch das Substantiv, dem -maya angefügt ist, bezeichnet wird.</p><blockquote><p>z.B. अन्नमय n. &quot;Überfluss an Speise&quot;</p></blockquote><p><img src="'+n+'" alt=""><br> Abb.: अन्नमयम्<br> विवाहः, Chennai = சென்னை<br> [Bildquelle: swamysk. -- <a href="http://www.flickr.com/photos/swamysk/2317923383/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/swamysk/2317923383/</a>. -- Zugriff am 2009-01-15. -- <a href="http://creativecommons.org/licenses/by-nc-nd/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung, keine kommerzielle Nutzung, keine Bearbeitung)]</p><h3 id="_52-2-3-तद्धित-suffix-eya" tabindex="-1">52.2.3. तद्धित-Suffix -eya <a class="header-anchor" href="#_52-2-3-तद्धित-suffix-eya" aria-label="Permalink to &quot;52.2.3. तद्धित-Suffix -eya&quot;">​</a></h3><p>Das तद्धित-Suffix -eya / f.: -eyī tritt u.a. an Feminina im Sinne von</p><ul><li><p>&quot;Kind der&quot;</p></li><li><p>&quot;Nachkomme der&quot;</p></li></ul><p>Dehnstufe (वृद्धि) des ersten Vokals.</p><blockquote><p>z.B. कौन्तेय m. &quot;Sohn der कुन्ती&quot;</p></blockquote><p><img src="'+l+'" alt=""><br> Abb.: भीमः कौन्तेयः<br> Wayang-Figur, Java, Indonesien<br> [Bildquelle. Wikipedia. Public domain]</p><h2 id="_52-3-adverbialbildung-adverbialsuffix-sas" tabindex="-1">52.3. Adverbialbildung: Adverbialsuffix -śas <a class="header-anchor" href="#_52-3-adverbialbildung-adverbialsuffix-sas" aria-label="Permalink to &quot;52.3. Adverbialbildung: Adverbialsuffix -śas&quot;">​</a></h2><p>Das Adverbialsuffix -śas bildet Adverbien von (hauptsächlich) distributiver Bedeutung aus:</p><ul><li>Zahlwörtern<br> Beispiele:<br> एकशस् &quot;einzeln, je einer&quot;<br> द्विशस् &quot;zu zweien, je zwei&quot;<br> शतशस् &quot;zu hunderten, je hundert&quot;</li><li>anderen Wörtern<br> Beispiele:<br> भागशस् &quot;Teil für Teil&quot;<br> सर्वशस् &quot;überall, gar alle&quot;<br> नित्यशस् &quot;beständig&quot;</li></ul><p><img src="'+o+'" alt=""><br> Abb.: अनुक्रमेणैकशः<br> Warteschlage vor Tempel, Trivandrum = Thiruvananthapuram = തിരുവനന്തപുരം<br> [Bildquelle: gray_area. -- <a href="http://www.flickr.com/photos/83831933@N00/3107232046/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/83831933@N00/3107232046/</a>. -- Zugriff am 2009-01-15. -- <a href="http://creativecommons.org/licenses/by-nc-sa/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung, keine kommerzielle Nutzung, share alike)]</p><h2 id="_52-4-verbalkomposita-die-ausdrucken-dass-etwas-zu-etwas-wird-oder-gemacht-wird-was-es-vorher-nicht-ist-अभुततद्भावः" tabindex="-1">52.4. Verbalkomposita, die ausdrücken, dass etwas zu etwas wird oder gemacht wird, was es vorher nicht ist (अभुततद्भावः) <a class="header-anchor" href="#_52-4-verbalkomposita-die-ausdrucken-dass-etwas-zu-etwas-wird-oder-gemacht-wird-was-es-vorher-nicht-ist-अभुततद्भावः" aria-label="Permalink to &quot;52.4. Verbalkomposita, die ausdrücken, dass etwas zu etwas wird oder gemacht wird, was es vorher nicht ist (अभुततद्भावः)&quot;">​</a></h2><h3 id="_52-4-1-cvi-bildungen" tabindex="-1">52.4.1. cvi-Bildungen <a class="header-anchor" href="#_52-4-1-cvi-bildungen" aria-label="Permalink to &quot;52.4.1. cvi-Bildungen&quot;">​</a></h3><p>Vor die Wurzeln</p><ul><li>कृ 8U &quot;tun&quot;</li><li>अस् 2P &quot;sein&quot;</li><li>भू 1P &quot;werden&quot;</li></ul><p>können Substantive und Adjektive als Präverbe gesetzt werden werden, um auszudrücken, dass jemand eine Person oder Sache zu dem macht, oder dass eine Person oder Sache zu dem wird, was durch jenes Nomen bezeichnet wird.</p><p>Der Auslaut des Nomens wird folgendermaßen behandelt:</p><ul><li>auslautendes -a und -ā deklinierbarer Wörter werden durch -ī ersetzt<br> Beispiele:<br> कृष्णीभवति &quot;etwas, das nicht schwarz ist, wird schwarz&quot;<br> कृष्णीकरोति &quot;er macht etwas, das nicht schwarz ist, schwarz&quot;<br> गङ्गीभवति &quot;er/sie wird zum Ganges&quot;</li><li>auslautendes -i und -u werden durch den entsprechenden Langvokal ersetzt<br> Beispiele:<br> शुचीभवति &quot;er/sie/es wird rein&quot;<br> गुरूभवामि &quot;ich werde Meister&quot;</li><li>auslautendes -ṛ wird durch --rī ersetzt<br> z.B. पित्रीभवति &quot;einer, der nicht Vater (पितृ) ist, wird Vater = ein Mann bekommt sein erstes Kind&quot;</li><li>auslautendes -n fällt ab und der vorausgehende Vokal wird nach den eben genannten Regeln behandelt<br> z.B. राजीबभूव &quot;einer (der nicht König war) wurde König (राजन्)&quot;</li><li>mehrstämmige andere Nomina stehen in der Form des Stammes, den sie im Lokativ (सप्तमी) Plural haben. Der Stamm unterliegt dann den üblichen Sandhiregeln. Siehe Kielhorn, Grammatik § 489,3.<br> z.B. तिर्यक्करोति &quot;er legt seitwärts (तिर्यच्)&quot;</li></ul><p><img src="'+s+'" alt=""><br> Abb.: भस्मीकृतं वनम् (भस्मन् n. &quot;Asche&quot;)<br> Brandrodung, Arunachal Pradesh = अरुणाचल प्रदेश<br> [Bildquelle: parrothanging. -- <a href="http://www.flickr.com/photos/biligiri/1857091269/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/biligiri/1857091269/</a>. -- Zugriff am 2009-01-15. --  <a href="http://creativecommons.org/licenses/by-nc-nd/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung, keine kommerzielle Nutzung, keine Bearbeitung)]</p><h3 id="_52-4-2-suffix-sat" tabindex="-1">52.4.2. Suffix -sāt <a class="header-anchor" href="#_52-4-2-suffix-sat" aria-label="Permalink to &quot;52.4.2. Suffix -sāt&quot;">​</a></h3><p>Um auszudrücken, dass eine Person oder Sache vollständig zu dem wird, oder dass jemand etwas oder jemand ganz und gar zu dem macht, was durch ein Nomen bezeichnet wird, kann an das Nomen</p><p>das Suffix -sāt (das nie -ṣāt wird)</p><p>angefügt werden und das so gebildete Wort mit den Wurzeln</p><ul><li>कृ 8U &quot;tun&quot;</li><li>अस् 2P &quot;sein&quot;</li><li>भू 1P &quot;werden&quot;</li><li>सम्-पद् 4Ā</li></ul><p>zu einem Verbalkompositum verbunden werden.</p><p>Beispiele:</p><blockquote><p>अग्निसाद्भवति । अग्निसात्संपद्यते  &quot;er wird vollständig zu Feuer&quot;</p><p>भस्मसात्करोति &quot;er verwandelt ganz und gar in Asche (भस्मन् n. &quot;Asche&quot;))</p></blockquote><p>Manchmal bedeutet das Suffix -sāt, dass eine Person oder Sache</p><ul><li>von dem abhängig wird oder</li><li>in den Besitz dessen übergeht</li><li>oder dass jemand von dem abhängig macht</li></ul><p>das vom Nomen bezeichnet wird</p><p>Beispiel:</p><blockquote><p>राजसाद्भवति &quot;er wird vom König abhängig, er wird Eigentum des Königs&quot;</p></blockquote><p>Nach den Bildungen mit -sāt werden Wurzeln nicht wie nach Präverben behandelt, also Absolutiv:</p><blockquote><p>भस्मसात्कृत्वा</p></blockquote><h2 id="_52-5-wortwiederholungen-द्विरुक्तम्" tabindex="-1">52.5. Wortwiederholungen (द्विरुक्तम्) <a class="header-anchor" href="#_52-5-wortwiederholungen-द्विरुक्तम्" aria-label="Permalink to &quot;52.5. Wortwiederholungen (द्विरुक्तम्)&quot;">​</a></h2><p>Wortwiederholung drückt im Sanskrit aus:</p><ul><li>Wiederholung der Handlung<br> z.B. पुनः पुनः &quot;immer wieder&quot;</li><li>Distribution<br> Beispiele:<br> पृथक्पृथक् &quot;je gesondert, je einzeln&quot;<br> यद्यद् ... तत्तद् &quot;was auch immer ... das alles&quot;<br> युगे युगे &quot;in jedem einzelnen Weltzeitalter&quot;</li></ul><p>Gelegentlich kann aus solchen Verbindungen ein Kompositum gebildet werden</p><p>Beispiele:</p><blockquote><p>एकैक 3 &quot;jeder einzelne&quot;<br> अल्पाल्प 3 &quot;ganz klein&quot;<br> नवनव 3 &quot;stets neu&quot;</p></blockquote><p>Zu den sog. आम्रेडित-Komposita, in denen flektierte Wörter wiederholt werden, das zweite aber in vorklassischer Zeit einen Akzent bekam, also ein Kompositum vorliegt, siehe Wackernagel, Altindische Grammatik II,1 S. 142ff.</p><h2 id="_52-6-das-zahlwort-सम्ख्या-f" tabindex="-1">52.6. Das Zahlwort (सम्ख्या f.) <a class="header-anchor" href="#_52-6-das-zahlwort-सम्ख्या-f" aria-label="Permalink to &quot;52.6. Das Zahlwort (सम्ख्या f.)&quot;">​</a></h2><p>Hier nicht behandeltes siehe z.B. bei Kielhorn, Grammatik §201f.</p><h3 id="_52-6-1-kardinalzahlen" tabindex="-1">52.6.1. Kardinalzahlen <a class="header-anchor" href="#_52-6-1-kardinalzahlen" aria-label="Permalink to &quot;52.6.1. Kardinalzahlen&quot;">​</a></h3><h4 id="_52-6-1-1-zahladjektive-fur-1-bis-19" tabindex="-1">52.6.1.1. Zahladjektive (für 1 bis 19) <a class="header-anchor" href="#_52-6-1-1-zahladjektive-fur-1-bis-19" aria-label="Permalink to &quot;52.6.1.1. Zahladjektive (für 1 bis 19)&quot;">​</a></h4><p>Die Zahlwörter für 1 bis 19 sind Adjektive.</p><p>Die Zahlwörter für 1 bis 4 sind für die drei Geschlechter in der Deklination unterschioedlich.</p><p>Für die Zahlwörter für 5 bis 19 (नवदशन्) gibt es nur eine einzige Deklination für die drei Geschlechter.</p><p>Für diese Zahladjektive gilt wie für alle Adjektive: es muss in gleichen Fall, Zahl und Geschlecht stehen wie das zugehörige Nomen und umgekehrt (d.h. für 1 Singular, für 2 Dual, für die übrigen Plural).</p><p>Zahladjektive:</p><blockquote><p>1 एक 3 (Deklination wie सर्व, im Plural: &quot;einige&quot;)<br> 2 द्वि 3<br> 3 त्रि 3<br> 4 चतुर् 3<br> 5 पञ्चन् 3<br> 6 षष् 3<br> 7 सप्तन् 3<br> 8 अष्टन् 3<br> 9 नवन् 3<br> 10 दशन् 3</p></blockquote><p>Die Deklination folgt an gegebener Stelle in den Wortlisten.</p><p>Die weiteren Zahladverbien bis 19 siehe z.B. bei Kielhorn, Grammatik §201.</p><h4 id="_52-6-1-2-zahlsubstantive-fur-19ff" tabindex="-1">52.6.1.2. Zahlsubstantive (für 19ff.) <a class="header-anchor" href="#_52-6-1-2-zahlsubstantive-fur-19ff" aria-label="Permalink to &quot;52.6.1.2. Zahlsubstantive (für 19ff.)&quot;">​</a></h4><p>Die Zahlwörter für 19 (एकोनविंशति &quot;eins weniger als 20&quot;) bis 99 sind feminine Substantive und werden wie मति f.  bzw. Wurzelnomina auf -t (z.B. त्रिंशत् f.) dekliniert.</p><p>Beispiele:</p><blockquote><p>20 विंशति f.<br> 30 त्रिंशत् f.</p></blockquote><p>Die Zahlwörter für Zahlen ab 100 sind neutrale Substantive. Sie werden wie फलम् dekliniert.</p><p>Beispiele:</p><blockquote><p>100 शत n.<br> 1000 सहस्र n.</p></blockquote><p>Die einzelnen Zahlsubstantive siehe z.B. bei Kielhorn, Grammatik §201.</p><h4 id="_52-6-1-3-syntaktisches-zu-den-kardinalzahlen" tabindex="-1">52.6.1.3. Syntaktisches zu den Kardinalzahlen <a class="header-anchor" href="#_52-6-1-3-syntaktisches-zu-den-kardinalzahlen" aria-label="Permalink to &quot;52.6.1.3. Syntaktisches zu den Kardinalzahlen&quot;">​</a></h4><p>Aus dem Unterschied zwischen Verbaladjektiven und Verbalsubstantiven für Kadinalzahlen ergibt sich folgende Konsequenz für die Syntax:</p><ul><li>adjektivische Kardinalzahlwörter können nur wie Adjektive mit dem Substantiv für das Gezählte verbunden werden<br> z.B. तिसृभिर्नारीभिः &quot;durch drei Frauen&quot;</li><li>substantivische Kardinalzahlwörter können auf drei Weisen mit dem Substantiv für das Gezählte verbunden werden <ul><li>sie regieren den Genetiv (षष्ठी) des Gezählten<br> z.B. विंशत्या नारीणाम् &quot;durch 20 Frauen&quot;</li><li>sie stehen als Apposition im selben Kasus (aber im Singular) wie das Gezählte<br> z.B. विंशत्या नारीभिः &quot;durch 20 Frauen&quot;</li><li>sie stehen als Hinterglied eines तत्पुरुष mit dem Gezählten als Vorderglied<br> z.B. गोविंशत्या &quot;durch 20 Kühe&quot;</li></ul></li></ul><h3 id="_52-6-2-ordinalzahlen" tabindex="-1">52.6.2. Ordinalzahlen <a class="header-anchor" href="#_52-6-2-ordinalzahlen" aria-label="Permalink to &quot;52.6.2. Ordinalzahlen&quot;">​</a></h3><p>Siehe z.B. bei Kielhorn, Grammatik §201f.</p><h3 id="_52-6-3-zahladverbien" tabindex="-1">52.6.3. Zahladverbien <a class="header-anchor" href="#_52-6-3-zahladverbien" aria-label="Permalink to &quot;52.6.3. Zahladverbien&quot;">​</a></h3><p>a) &quot;-mal&quot;:</p><blockquote><p>einmal: सकृत्<br> zweimal: द्विस्<br> dreimal: त्रिस्<br> viermal: चतुस्<br> fünfmal usw. wird mit dem Suffix -कृत्वस् gebildet: पञ्चकृत्वस्</p></blockquote><p>b) &quot;-fach&quot;: wird mit dem Suffix -धा ausgedrückt</p><blockquote><p>einfach: एकधा<br> zweifach: द्विधा । द्वेधा<br> usw.</p></blockquote><p>c) &quot;je ...&quot;, &quot;zu ...&quot;: wird mit dem Suffix -शस् ausgedrückt (siehe oben!)</p><blockquote><p>द्विशस् &quot;zu zweien, je zwei&quot;</p></blockquote><h3 id="_52-6-4-zahladjektive" tabindex="-1">52.6.4. Zahladjektive <a class="header-anchor" href="#_52-6-4-zahladjektive" aria-label="Permalink to &quot;52.6.4. Zahladjektive&quot;">​</a></h3><p>&quot;-fältig&quot;:</p><blockquote><p>zweifältig, aus zweien bestehend<br> dreifältig, aus drei Teilen bestehend</p><p>ab 4 wird &quot;-fältig&quot; durch das Suffix -तय (f.: -तयी) ausgedrückt: चतुष्टय m.n. चतुष्टयी f. &quot;vierfältig&quot;</p></blockquote><p>Weitere Bildungen entnehme man den Wörterbüchern oder Grammatiken.</p><h3 id="_52-6-5-komposita-mit-kardinalzahlen-im-vorderglied" tabindex="-1">52.6.5. Komposita mit Kardinalzahlen im Vorderglied <a class="header-anchor" href="#_52-6-5-komposita-mit-kardinalzahlen-im-vorderglied" aria-label="Permalink to &quot;52.6.5. Komposita mit Kardinalzahlen im Vorderglied&quot;">​</a></h3><p>बहुव्रीहि dieser Art werden ganz regelmäßig gebildet.</p><p>Beispiel:</p><blockquote><p>चतुर्मुख m. &quot;einer, der vier Gesichter hat&quot; = चत्वारि मुखानि यस्य सः (ein Beiname Brahmās)</p></blockquote><p><img src="'+d+'" alt=""><br> Abb.: चतुर्मुखः<br> [Bildquelle: Wikipedia. Public domain]</p><p>तत्पुरुष mit einer Kardinalzahl im Vorderglied dürfen nicht beliebig gebildet werden:</p><p>Regel 1: Wörter, die eine Himmelsrichtung bezeichnen (wie पूर्व 3 &quot;östlich&quot;, उत्तर 3 &quot;nördlich&quot;), und Wörter für Kardinalzahlen dürfen mit anderen Wörtern nur dann ein कर्मधारय-Kompositum bilden, wenn das Kompositum als Eigenname gebraucht wird.</p><p>Daher darf z.B. aus उत्तरा वृक्षाः &quot;nördliche Bäume&quot; oder पञ्च ब्राह्मणः kein Tatpuruṣa gebildet werden. Aus सप्तन् und ऋषि kann aber der Tatpuruṣa सप्तर्षि m. &quot;die sieben Ṛṣis&quot; gebildet werden, wenn dies als Name für das Sternbild des Großen Bären (Ursa maior) steht.</p><p><img src="'+u+'" alt=""><br> Abb.: सप्तर्षयः<br> Das Siebengestirn = die sieben hellsten Sterne des Großen Bären (Ursa maior)<br> [Bildquelle: Wikipedia, GNU FDLicense]</p><p>Regel 2: Abweichend von Regel 1 kann ein Wort, das eine Himmelrichtung oder eine Kardinalzahl bezeichnet mit einem anderen Nomen ein Tatpuruṣa bilden, wenn</p><ol><li>dem so gebildeten Kompositum ein Taddhita-Suffix angefügt wird<br> Beispiele:<br> pūrva + śālā (&quot;Halle) » *pūrvaśālā (darf so nicht gebraucht werden!) + Taddhita -a » पौर्वशाल 3 &quot;in der östlichen Halle befindlich&quot;<br> ṣaṣ + mātṛ » *ṣaṇmātṛ (nicht zulässig!) + Taddhita -a » षण्मातुर m. &quot;das Kind von sechs Müttern&quot; (=  कार्त्तिकेय)</li><li>das so gebildete Kompositum in einer Bedeutung gebraucht wird, die sonst durch ein Taddhita-Suffix bezeichnet wird (bei dieser Art ist der Übergang zum Bahuvrīhi fließend):<br> Beispiele:<br> dvi + go » द्विगु : nicht: &quot;zwei Kühe&quot;, sondern: &quot;für zwei Kühe erhandelt&quot;<br> द्विवर्ष nicht: &quot;zwei Jahre&quot;, sondern: &quot;zwei Jahre alt&quot;</li><li>das so gebildete Kompositum das Vorderglied eines anderen Kompositums bildet<br> Beispiel:<br> pañca + go » pañcagava (als Einzelwort unzulässig!) + dhana » पञ्चगवधन m. &quot;Einer, dessen Reichtum fünf Kühe sind&quot;</li></ol><p><img src="'+h+'" alt=""><br> Abb.: षण्मातुरः कार्त्तिकेय:<br> Jalakandapuram = ஜலகண்டபுரம்<br> [Bildquelle: Wikipedia. Public domain]</p><p>Eine Bezeichnung für eine Kardinalzahl (aber nicht für eine Himmelsrichtung) kann als Vorderglied mit einem anderen Nomen auch dann ein Tatpuruṣa bilden, wenn das so gebildete Kompositum das Aggregat mehrerer Dinge bezeichnet, d.h. zwei oder mehrere Dinge zu einer Einheit zusammenfasst.</p><p>Tatpuruṣa, die nach dieser Regel gebildet werden heißen Dvigu (द्विगु).</p><p>Dvigu-Komposita, die eine Einheit bezeichnen, sind gewöhnlich Neutra. Endet das zweite Glied auf -a, so kann das Femininsuffix -ī antreten. Endet das zweite Glied auf fem. -ā, so tritt an dessen Stelle entweder Neutrum -a oder Feminin -ī. Endet das zweite Glied auf -an, so wird dafür -a oder -ī substituiert.</p><p>Beispiele:</p><blockquote><p>त्रि + भुवनव् » त्रिभुवन n. &quot;das Aggregat der drei Welten, die drei Welten als Einheit, die Dreiwelt (Himmel-Erde-Unterwelt)</p><p>त्रिलोक n. । त्रिलोकी n. &quot;Dreiwelt&quot;</p></blockquote><p>Dvigu-Komposita, denen kein Taddhitasuffix angefügt ist, die aber die Bedeutung haben, die durch ein Taddhita-Suffix bezeichnet wird, richten wie Bahuvrīhis ihr Geschlecht nach dem Nomen, welches sie näher bestimmen (es sind in Wirklichkeit wohl Bahuvrīhi)</p><p>Beispiel:</p><blockquote><p>पञ्चगु 3: &quot;für fünf Kühe erhandelt&quot;</p></blockquote><h2 id="_52-7-wortliste" tabindex="-1">52.7. Wortliste <a class="header-anchor" href="#_52-7-wortliste" aria-label="Permalink to &quot;52.7. Wortliste&quot;">​</a></h2><p>अखिल 3: lückenlos, ganz</p><p>निखिल 3: vollständig, ganz</p><blockquote><p>von:</p><p>खिल m.: Brachfeld, Ödland</p></blockquote><p><img src="'+b+'" alt=""><br> Abb.: खिलः<br> Tambhol, Akole, Ahmednagar = अहमदनगर<br> [Bildquelle: Dan Tunstall / World Resources Institute Staff. -- <a href="http://www.flickr.com/photos/wricontest/291696431/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/wricontest/291696431/</a>. -- Zugriff am 2009-01-16. -- <a href="http://creativecommons.org/licenses/by/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung)]</p><p>अन्तर् Adv.: innen, im Innern ; Postposition mit Gen. Lok. (षष्टी, सप्तमी): innerhalb, inmitten ; Postposition mit Gen. Abl. (षष्ठी, पञ्चमी): aus ... heraus</p><p>अन्योन्य 3: gegenseitig, einander</p><p>इ + वि + परि 2P विपर्येति : fehlschlagen</p><blockquote><p>PPP विपरीत 3: verkehrt, falsch</p></blockquote><p>त्रि 3: drei</p><blockquote><table tabindex="0"><thead><tr><th></th></tr></thead><tbody><tr><td>Maskulinum</td></tr><tr><td>पुंस्</td></tr><tr><td>नपुंसकम्</td></tr><tr><td>स्त्री</td></tr><tr><td>त्रयस्</td></tr><tr><td>1. Nominativ</td></tr><tr><td>१. प्रथमा</td></tr><tr><td>2. Akkusativ</td></tr><tr><td>२. द्वितीया</td></tr><tr><td>3. Instrumentalis</td></tr><tr><td>३. तृतीया</td></tr><tr><td>4. Dativ</td></tr><tr><td>४. चतुर्थी</td></tr><tr><td>5. Ablativ</td></tr><tr><td>५. पञ्चमी</td></tr><tr><td>6. Genetiv</td></tr><tr><td>६. षष्ठी</td></tr><tr><td>7. Lokativ</td></tr><tr><td>७. सप्तमी</td></tr></tbody></table></blockquote><p>निस् Postposition und Präfix bei Nomina und Verben: hinaus, hinweg, heraus, hervor, aus, weg, ohne - von</p><p>पीड् 10P पीडयति : drücken, quälen ; bedrängen, belagern, plagen</p><p><img src="'+p+'" alt=""><br> Abb.: पीडिताः<br> Hyderabad = హైదరాబాద్<br> [Bildquelle: David A G Wilson. -- <a href="http://www.flickr.com/photos/dawilson/2912554387/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/dawilson/2912554387/</a>. -- Zugriff am 2009-01-16. -- <a href="http://creativecommons.org/licenses/by-nc-nd/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung, keine kommerzielle Nutzung, keine Bearbeitung)]</p><p>पर 3: (Deklination wie सर्व) fernstehend, fremd, höher als (पञ्चम्या), äußerster, höchster ; anderer, fremder, feindlich ; m.: Fremder</p><blockquote><p>davon:</p><p>परम् Adv.: in hohem Grade, darauf, später, aber, jedoch</p></blockquote><p>प्रति Postposition (द्वितीयया): zu - hin, nach, in Bezug auf, gegenüber</p><p>प्रधान 3: hauptsächlicher, bester ; n.: Wichtigstes</p><p><img src="'+m+'" alt=""><br> Abb.: प्रधानः<br> मुंबई<br> [Bildquelle: saibotregeel. -- <a href="http://www.flickr.com/photos/saibotregeel/330885607/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/saibotregeel/330885607/</a>. -- Zugriff am 2009-01-16. -- <a href="http://creativecommons.org/licenses/by-nd/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung, keine Bearbeitung)]</p><p>लौल्य n.: Gier, Lüsternheit</p><p>वर्ग m.: Abschnitt, Abteilung, Schar</p><blockquote><p>त्रिवर्ग m.: Dreiergruppe (z.B. धर्मः, अर्थः, कामः ; oder: सत्त्वम्, रजस्, तमस् ; oder: ब्राह्मणाः, क्षत्रियाः, वैश्याः)</p></blockquote><p>वश् 2P वस्टि, उशन्ति, Imperat. 2.sg.: उड्ढि : wollen, gebieten, verlangen nach</p><blockquote><p>Perf Va उवाश, ऊशुर्<br> Fut. वशिष्यति<br> Pass. उष्यते<br> Kaus. वाशयति<br> PPP उशित<br> Inf. वशितुम्<br> Absol. -वश्य</p></blockquote><p>वा 2P वाति : wehen, blasen</p><blockquote><p>Perf IV ववौ<br> Fut. वास्यति<br> Pass. वायते<br> Kaus. वापयति<br> PPP वान । वात<br> Inf. वातुम्</p><p>davon:</p><p>वात m.: Wind</p></blockquote><p>वृज् 7P वृणक्ति 1P वर्जति : wenden, drehen ; abwehren, ausschließen</p><blockquote><p>Perf. II ववर्ज, ववृजुर्<br> Fut. वर्जिष्यति<br> Pass. वृज्यते<br> Kaus. वर्जयति : beseitigen<br> Kaus. PPP वर्जित : einer Sache verlustig, frei von<br> PPP वृक्त<br> Inf. वर्जितुम्</p></blockquote><p>व्यवहार m.: Treiben, Wandel, Umgang, Verkehr, Geschäft, Handel, (Gerichts-)Prozess</p><p>शील n.: Brauch, Gewohnheit, Natur, Charakter, gute Gewohnheit = Moral</p><p>सूर्य m.: Sonne</p><p>सेव् 1Ā सेवते : jemandem (द्वितीया) dienen, aufwarten, ehren, lieben</p><blockquote><p>Perf I सिषेवे<br> Fut. सेविष्यते<br> Pass. सेव्यते<br> Kaus. सेवयति<br> PPP सेवित<br> Inf. सेवितुम्<br> Absol. -सेव्य</p><p>davon:</p><p>सेवा f.: Dienst, Aufwartung</p></blockquote><p>धीर 3: fest, standhaft, kontinuierlich, beharrlich</p><p>शम् शाम्यति</p><blockquote><p>शशाम, शेमुर्<br> शमिष्यति<br> शम्यते<br> शमयति<br> शान्त<br> शमित्वा । शान्त्वा</p></blockquote><p>कोविद 3: erfahren in (षष्ठ्या सप्तम्या वा)</p><p>याम m.: Nachtwache (jeweils drei Stunden)</p><p>परंपरा f.: ununterbrochene Reihe</p><p>अमुत्र Adv.: dort, dorthin</p><p>च्यु 1Ā च्यवते : sich rühren, sich fortbewegen, herabfallen</p><blockquote><p>Perf. IIIa चुच्युवे<br> Fut. च्योष्यते<br> Pass. च्यूयते<br> Kaus. च्यावयति<br> PPP च्युत</p></blockquote><p>भू + अनु 1P अनुभवति : erkennen, empfinden, wahrnehmen, erfahren</p><p>चक्र n.: Rad</p><p><img src="'+c+'" alt=""><br> Abb.: चक्रम्<br> Konark = कोनार्क<br> [Bildquelle: Gaurab Arka. -- <a href="http://www.flickr.com/photos/gaurabarka/2758427709/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/gaurabarka/2758427709/</a>. -- Zugriff am 2009-01-16. --  <a href="http://creativecommons.org/licenses/by-nc-nd/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung, keine kommerzielle Nutzung, keine Bearbeitung)]</p><p>कदली f.: Bananenbaum (<em>Musa</em> sp.)</p><p><img src="'+g+'" alt=""><br> Abb.: कदली<br> Hampi = ಹಂಪೆ<br> [Bildquelle: oliver hiltbrunner. -- <a href="http://www.flickr.com/photos/oliverhiltbrunner/757794766/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/oliverhiltbrunner/757794766/</a>. -- Zugriff am 2009-01-15. -- <a href="http://creativecommons.org/licenses/by-nc-sa/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung, keine kommerzielle Nutzung, share alike)]</p><p>सार m.n.: Kern, Mark, Essenz, Substanz</p><p>दिव्य 3: himmlisch, göttlich</p><p>वर 3: bester</p><p>आदर्श m.: Spiegel</p><p>मल m.n.: Schmutz, Makel</p><p><img src="'+f+'" alt=""><br> Abb.: मलम्<br> मुंबई<br> [Bildquelle: James Cridland. -- <a href="http://www.flickr.com/photos/jamescridland/187997905/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/jamescridland/187997905/</a>. -- Zugriff am 2009-01-16. -- <a href="http://creativecommons.org/licenses/by/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung)]</p><p>त्रिपिष्टप n.: Indras Himmel</p><p>मार m.: das personifizierte Böse, die personifizierte Verführung / Manipulation, Teufel</p><p><img src="'+k+'" alt=""><br> Abb.: Māras Angriff auf Buddha<br> Amaravati = అమరావతి, 2. Jhdt. n. Chr.<br> [Bildquelle. Wikipedia. GNU FDLicense]</p><p>विजिज्ञासु 3: jemand, der völlig erkennen will</p><p>त्रै 1Ā त्रायते : beschützen, retten</p><blockquote><p>Perf. IV तत्रे<br> Fut. त्रास्यते<br> Pass. त्रायते<br> Kaus. त्रापयति<br> PPP त्राण । त्रात<br> Inf. त्रातुम्</p></blockquote><h2 id="_52-8-ubersetzungsubung" tabindex="-1">52.8. Übersetzungsübung <a class="header-anchor" href="#_52-8-ubersetzungsubung" aria-label="Permalink to &quot;52.8. Übersetzungsübung&quot;">​</a></h2><p>१. मनुस्मृति ४, १५९ - १६१</p><blockquote><p>यद्यत्परवशं कर्म<br> ततद्यत्नेन वर्जयेत् ।<br> यद्यदात्मवशं तु स्यात्<br> ततत्सेवेत यत्नतः ॥१५९॥</p><p>सर्वं परवशं दुःखं<br> सर्वमात्मवशं सुखम् ।<br> एतद्विद्यात्समासेन<br> लक्षणं सुखदुःखयोः ॥१६०॥</p><p>यत्कर्म कुर्वतो ऽस्य स्यात्<br> परितोषो ऽन्तरात्मनः ।<br> तत्प्रयत्नेन कुर्वीत<br> विपरीतं तु वर्जयेत् ॥१६१॥</p><p>Erklärung: सुखदुःखयोः Gen.Lok.Dual.m.f.n. (Dualdvandva)</p></blockquote><p>२. मनुस्मृति २, ६ Über die Quellen des धर्म</p><blockquote><p>वेदो ऽखिलो धर्ममूलम्<br> स्मृतिशीले च तद्विदाम् ।<br> आचआरश्चैव साधूनाम्<br> आत्मनस्तुष्टिरेव च ॥६॥</p><p>Erklärung:  स्मृतिशीले Nom.Akk.Dual.n. (Dualdvandva)</p></blockquote><p>३. कौटिलीयार्थशास्त्र १, ७, २ - ७ Über अर्थ, काम, धर्म im Leben des Fürsten</p><p>एवं वश्येन्द्रियः परस्त्रीद्रव्यहिंसाश्च वर्जयेत्, स्वप्नं लौल्यमनृतम्दुद्धतवेषत्वमनर्थ्यसंयोगमधर्मसंयुक्तमनर्थसंयुक्तं च व्यवहारम् ।२। धर्मार्थाविरोधेन कामं सेवेत, न निःसुखः स्यात् ।३। समं वा त्रिवर्गमन्योन्यानुबद्धम् ।४। एको ह्यत्यासेवितो धर्मार्थकामानामात्मानमितरौ च पीदयति ।५। अर्थ एव प्रधान इति कौटिल्यः ।६। अर्थमूलौ हि धर्मकामाविति ।७।</p><blockquote><p>Erklärungen:</p><p>इतरौ Nom.Akk.Dual.m zu इतर 3 &quot;anderer&quot;</p><p>अर्थमूलौ, धर्मकामौ Nom.Akk.Dual.m (धर्मकामौ ist Dualdvandva)</p></blockquote><p>४. अश्वघोष (2. Jhdt. n. Chr.): बुद्धचरित ४ Buddhas erlösende Erkenntnis</p><p><img src="'+q+'" alt=""><br> Abb.: अश्वत्थो महाबोधिवृक्षः<br><em>Ficus religiosa</em> L.<br> बोधगया, ca. 1810<br> [Bildquelle: Wikipedia. Public domain]</p><blockquote><p>ततो मारबलं जित्वा<br> धैर्येण च शमेन च ।<br> परमार्थं विजिज्ञासुः<br> स दद्ध्यौ ध्यानकोविदः ॥१॥</p><p>सर्वेषु ध्यानविधिषु<br> प्राप्य चैश्वर्यमुत्तमम् ।<br> सस्मार प्रथमे याम<br> पूर्वजन्मपरंपराम् ॥२॥</p><p>अमुत्राहमयं नाम<br> च्युतस्तस्मादिहागतः ।<br> इति जन्मसहस्राणि<br> सस्मारानुभवन्निव ॥३॥</p><p>स्मृत्वा जन्म च मृत्युं च<br> तासु तासूपपत्तिषु ।<br> ततः सत्त्वेषु कारुण्यम्<br> चकार करुणात्मकः ॥४॥</p><p>कृत्वेह स्वजनोत्सर्गम्<br> पुनरन्यत्र च कृत्वा ।<br> अत्राणः खलु लोको ऽयम्<br> परिभ्रमति चक्रवत् ॥५॥</p><p>इत्येवं स्मरतस्तस्य<br> बभूव नियतात्मनः ।<br> कदलीगर्भनिःसारः<br> संसार इति निश्चयः ॥६॥</p><p>द्वितीये त्वागते यामे<br> सो ऽद्वितीयपराक्रमः ।<br> दिव्यं लेभे परं चक्षुः<br> सर्वचक्षुष्मतां वरः ॥७॥</p><p>ततस्तेन स दिव्येन<br> परिशुद्धेन चक्षुषा ।<br> ददर्श निखिलं लोकम्<br> आदर्श इव निर्मले ॥८॥</p><p>सत्त्वानां पश्यतस्तस्य<br> निकृष्टोत्कृष्तकर्मणाम् ।<br> प्रच्युतिं चोपपत्तिं च<br> ववृधे करुणात्मता ॥९॥</p><p>इमे दुष्कृतकर्माणः<br> प्राणिनो यान्ति दुर्गतिम् ।<br> इमे ऽन्ये शुभकर्माणः<br> प्रतिष्ठन्ते त्रिविष्टपे ॥१०॥</p></blockquote><h2 id="_52-9-aufgaben-wahrend-der-semesterferien" tabindex="-1">52.9. Aufgaben während der Semesterferien <a class="header-anchor" href="#_52-9-aufgaben-wahrend-der-semesterferien" aria-label="Permalink to &quot;52.9. Aufgaben während der Semesterferien&quot;">​</a></h2><p>Mit Lektion 52 ist das erste Semester (13 Wochen á 4 Unterrichtsstunden) des Sanskritkurses beendet.</p><p>Während der Semesterferien sollten folgende Aufgaben erfüllt werden:</p><ol><li>Wiederholung des gesamten bisher Gelernten, besonders: <ol><li>Auswendiglernen der Konjugations- und Deklinationsparadigmen</li><li>Wörter</li><li>Stammformen</li></ol></li><li>Auswendiglernen möglichst vieler Verse und Prosatexte aus dem klassischen Schrifttum</li><li>Durcharbeiten von <a href="./lektion53">Lektion 53</a></li><li>Durcharbeiten der Blätter Bhg 1 - 11 (noch nicht im Internet)</li><li>Vorbereitung von भगवद्गीता Kap. 1, Lernen der dazugehörigen Wörter auf den Wortlisten (noch nicht im Internet)</li><li>Metrische Analyse aller Verse von भगवद्गीता १<br> Einen guten Eindruck von dem Text in rezitierter Form gibt: <a href="http://www.vaisnava.cz/gita/mp3/Bhagavad-gita01.mp3" target="_blank" rel="noreferrer">http://www.vaisnava.cz/gita/mp3/Bhagavad-gita01.mp3</a>. -- Zugriff am 2009-01-19</li><li>Lesen einer महाभारत-Nacherzählung, z.B.<br> Mahābhārata : Indiens grosses Epos / aus dem Sanskrit übers. und zsgef. von Biren Roy. -- 10. Aufl. -- München : Diederichs, 1995. -- 335 S.  ; 19 cm. --  (Diederichs gelbe Reihe ; 16 : Indien)</li><li>Durcharbeiten:**<br> Kunnappally, John:** Prakriyā bhāshyam : Sanskrit grammar / Originally written in Malayalam. Translated into English by K.V.R. Pai. -- Parathode : Selbstverl., 1983. -- 818 S. ; 23 cm. -- S. 208 - 254 (Sytactical government)</li><li>Fertig durcharbeiten von:**<br> Basham**, A. L. (Arthur Llewellyn) &lt;1914-1986&gt;The wonder that was IndiaTeil: A survey of the culture of the Indian sub-continent before the coming of the Muslims. -- London : Sidgwick &amp; Jackson, 1954.</li><li>Beginn mit der Durcharbeit von:<br><strong>Winternitz, Moriz</strong> &lt;1863 - 1937&gt;<strong>:</strong> Geschichte der indischen Literatur. Stuttgart : Koehler. -- 3 Bde. -- 1908 - 1922 (immer noch die bei weitem beste Literaturgeschichte der Sanskrit-, Pali- und Prakritliteratur)</li></ol><p><img src="'+w+'" alt=""><br> Abb.: श्रीगुम्पिः , मम मन्त्री<br> (Bild: Payer)</p>',197)])])}const y=r(z,[["render",v]]);export{K as __pageData,y as default};
